interface FrameCodec<TIn, TOut> {
    fun encode(payload: TIn): String
    /** Decode a chunk; appends parsed payloads into [buffer]. */
    fun decode(chunk: String, buffer: MutableList<TOut>)
    fun decodeBinary(chunk: ByteArray, buffer: MutableList<TOut>)
}

/**
 * PVE termproxy text framing.
 *
 * Encoding (client → server) uses `0:LEN:PAYLOAD` (data),
 * `1:COLS:ROWS:` (resize), `2` (ping).
 *
 * Decoding (server → client) is **pass-through**: PVE's termproxy is
 * asymmetric — server→client is the raw underlying TTY output (escape
 * sequences and all), not framed. The only framed inbound message is
 * the initial "OK" ack, which appears immediately after the in-band
 * `<user>:<vncticket>\n` handshake and is harmless to surface verbatim.
 */
class TextFrameCodec : FrameCodec<String, String> {
    companion object {
        const val PING_FRAME = "2"
        fun encodeResize(cols: Int, rows: Int): String = "1:$cols:$rows:"
    }

    override fun encode(payload: String): String = "0:${payload.length}:$payload\n"

    override fun decode(chunk: String, buffer: MutableList<String>) {
        if (chunk.isNotEmpty()) buffer.add(chunk)
    }

    override fun decodeBinary(chunk: ByteArray, buffer: MutableList<String>) {
        if (chunk.isNotEmpty()) buffer.add(chunk.toString(Charsets.UTF_8))
    }
}

/** VNC: raw RFB protocol bytes pass through unchanged. */
class BinaryFrameCodec : FrameCodec<ByteArray, ByteArray> {
    override fun encode(payload: ByteArray): String = throw UnsupportedOperationException("VNC payloads are binary")
    override fun decode(chunk: String, buffer: MutableList<ByteArray>) {
        buffer.add(chunk.toByteArray(Charsets.UTF_8))
    }
    override fun decodeBinary(chunk: ByteArray, buffer: MutableList<ByteArray>) {
        buffer.add(chunk)
    }
}

