/** Open/closed: add new flow → new issuer object, no edits below. */
object DefaultTerminalTicketIssuer : TerminalTicketIssuer {
    override fun issue(baseUrl: String, httpClient: okhttp3.Call.Factory, target: TerminalTarget): IssuedTicket = when (target) {
        is TerminalTarget.Node -> IssuedTicket(
            // PVE rejects POSTs with `Content-Type: application/json` and a zero-byte
            // body ("malformed JSON string ..."). The Kotlin generator's ApiClient
            // sends `EMPTY_REQUEST` (0 bytes) when the typed body is null, so we
            // construct an explicit empty DTO to force `{}` on the wire.
            parseTicket(NodesApi(baseUrl, httpClient).nodesTermproxy(target.node, NodesTermproxyRequest()).data),
            "/nodes/${encode(target.node)}",
        )
        is TerminalTarget.Qemu -> IssuedTicket(
            parseTicket(QemuApi(baseUrl, httpClient).qemuTermproxy(target.node, target.vmid, QemuTermproxyRequest()).data),
            "/nodes/${encode(target.node)}/qemu/${target.vmid}",
        )
        is TerminalTarget.Lxc -> IssuedTicket(
            // LXC termproxy has no request body in the spec — call without one.
            parseTicket(LxcApi(baseUrl, httpClient).lxcTermproxy(target.node, target.vmid).data),
            "/nodes/${encode(target.node)}/lxc/${target.vmid}",
        )
    }
}

object DefaultVncTicketIssuer : VncTicketIssuer {
    override fun issue(baseUrl: String, httpClient: okhttp3.Call.Factory, target: VncTarget): IssuedTicket = when (target) {
        is VncTarget.NodeShell -> IssuedTicket(
            parseTicket(NodesApi(baseUrl, httpClient).nodesVncshell(target.node).data),
            "/nodes/${encode(target.node)}",
        )
        is VncTarget.Qemu -> IssuedTicket(
            parseTicket(QemuApi(baseUrl, httpClient).qemuVncproxy(target.node, target.vmid).data),
            "/nodes/${encode(target.node)}/qemu/${target.vmid}",
        )
        is VncTarget.Lxc -> IssuedTicket(
            parseTicket(LxcApi(baseUrl, httpClient).lxcVncproxy(target.node, target.vmid).data),
            "/nodes/${encode(target.node)}/lxc/${target.vmid}",
        )
    }
}

internal fun parseTicket(raw: Any?): ConsoleTicket {
    @Suppress("UNCHECKED_CAST")
    val obj = (raw as? Map<String, Any?>) ?: throw IllegalStateException("ticket payload is not a map: $raw")
    val ticket = obj["ticket"] as? String ?: throw IllegalStateException("ticket field missing")
    val port = when (val p = obj["port"]) {
        is Number -> p.toInt()
        is String -> p.toIntOrNull()
        else -> null
    } ?: throw IllegalStateException("port field missing or not numeric")
    return ConsoleTicket(
        ticket = ticket,
        port = port,
        user = obj["user"] as? String ?: "",
        upid = obj["upid"] as? String,
        cert = obj["cert"] as? String,
    )
}

