interface AuthAttacher {
    fun headers(): Map<String, String>
}

class CompositeAuthAttacher(private val inner: List<AuthAttacher>) : AuthAttacher {
    override fun headers(): Map<String, String> = inner.fold(mutableMapOf()) { acc, a ->
        acc.putAll(a.headers()); acc
    }
}

class TokenAuthAttacher : AuthAttacher {
    override fun headers(): Map<String, String> {
        val out = mutableMapOf<String, String>()
        ApiClient.accessToken?.takeIf { it.isNotEmpty() }?.let {
            out["Authorization"] = "PVEAPIToken=$it"
        }
        ApiClient.apiKey["Authorization"]?.takeIf { it.isNotEmpty() }?.let {
            val prefix = ApiClient.apiKeyPrefix["Authorization"] ?: ""
            out["Authorization"] = if (prefix.isEmpty()) it else "$prefix $it"
        }
        return out
    }
}

class CookieAuthAttacher : AuthAttacher {
    override fun headers(): Map<String, String> =
        ApiClient.apiKey["PVEAuthCookie"]?.takeIf { it.isNotEmpty() }?.let {
            mapOf("Cookie" to "PVEAuthCookie=$it")
        } ?: emptyMap()
}

internal val defaultAuth: AuthAttacher = CompositeAuthAttacher(
    listOf(TokenAuthAttacher(), CookieAuthAttacher()),
)

