interface WebSocketTransport {
    fun open(url: String, headers: Map<String, String>, listener: WebSocketListener): WebSocket
}

class OkHttpWebSocketTransport(private val client: OkHttpClient = ApiClient.defaultClient) : WebSocketTransport {
    override fun open(url: String, headers: Map<String, String>, listener: WebSocketListener): WebSocket {
        val builder = Request.Builder().url(url)
        for ((k, v) in headers) builder.header(k, v)
        return client.newWebSocket(builder.build(), listener)
    }
}

internal val defaultTransport: WebSocketTransport = OkHttpWebSocketTransport()

// ─────────────────────────────────────────────────────────────────────────────
// UrlBuilder
// ─────────────────────────────────────────────────────────────────────────────

internal object UpgradeUrlBuilder {
    fun build(baseUrl: String, basePath: String, ticket: ConsoleTicket): String {
        val ws = when {
            baseUrl.startsWith("https://") -> "wss://" + baseUrl.removePrefix("https://")
            baseUrl.startsWith("http://") -> "ws://" + baseUrl.removePrefix("http://")
            else -> baseUrl
        }.trimEnd('/')
        return "$ws$basePath/vncwebsocket?port=${ticket.port}&vncticket=${encode(ticket.ticket)}"
    }
}

