// Sessions
// ─────────────────────────────────────────────────────────────────────────────

abstract class BaseSession {
    @Volatile protected var closed = false

    abstract fun close(code: Int = 1000, reason: String = "client closed")
}

class TerminalSession internal constructor(
    transport: WebSocketTransport,
    request: BuiltRequest,
    private val ticket: ConsoleTicket,
    private val needsInbandAuth: Boolean,
    private val onMessage: (String) -> Unit,
    private val onClose: (Int, String) -> Unit,
    private val onError: (Throwable) -> Unit,
) : BaseSession() {
    private val codec = TextFrameCodec()
    private val socket: WebSocket
    private val pinger = Executors.newSingleThreadScheduledExecutor { r ->
        Thread(r, "pve-termproxy-ping").apply { isDaemon = true }
    }

    init {
        // OkHttp's `newWebSocket` returns immediately; `onOpen` fires
        // asynchronously once the upgrade completes. PVE termproxy
        // expects `<user>:<vncticket>\n` as the **very first** frame
        // after the handshake — without it the daemon times out and
        // drops the connection ~10 s later. So we (a) await `onOpen`
        // before allowing any sends, and (b) push the in-band auth
        // before scheduling the keepalive pinger.
        val openLatch = CountDownLatch(1)
        val openError = AtomicReference<Throwable?>(null)
        socket = transport.open(request.url, request.headers, object : WebSocketListener() {
            override fun onOpen(webSocket: WebSocket, response: Response) {
                openLatch.countDown()
            }
            override fun onMessage(webSocket: WebSocket, text: String) {
                val out = mutableListOf<String>()
                codec.decode(text, out)
                out.forEach(onMessage)
            }
            override fun onMessage(webSocket: WebSocket, bytes: ByteString) {
                val out = mutableListOf<String>()
                codec.decodeBinary(bytes.toByteArray(), out)
                out.forEach(onMessage)
            }
            override fun onClosed(webSocket: WebSocket, code: Int, reason: String) {
                if (openLatch.count > 0L) {
                    openError.set(IOException("WebSocket closed before open: $code $reason"))
                    openLatch.countDown()
                }
                closed = true
                pinger.shutdownNow()
                onClose(code, reason)
            }
            override fun onFailure(webSocket: WebSocket, t: Throwable, response: Response?) {
                if (openLatch.count > 0L) {
                    openError.set(t)
                    openLatch.countDown()
                }
                if (!closed) onError(t)
                closed = true
                pinger.shutdownNow()
            }
        })
        if (!openLatch.await(30L, TimeUnit.SECONDS)) {
            socket.cancel()
            throw IOException("WebSocket open timeout after 30s")
        }
        openError.get()?.let { err ->
            socket.cancel()
            throw IOException("WebSocket failed to open: ${err.message}", err)
        }
        if (needsInbandAuth) {
            socket.send("${ticket.user}:${ticket.ticket}\n")
        }
        pinger.scheduleAtFixedRate(
            { if (!closed) socket.send(TextFrameCodec.PING_FRAME) },
            PING_INTERVAL_S, PING_INTERVAL_S, TimeUnit.SECONDS,
        )
    }

    fun send(text: String) { socket.send(codec.encode(text)) }
    fun resize(cols: Int, rows: Int) { socket.send(TextFrameCodec.encodeResize(cols, rows)) }

    override fun close(code: Int, reason: String) {
        closed = true
        pinger.shutdownNow()
        socket.close(code, reason)
    }
}

class VncSession internal constructor(
    transport: WebSocketTransport,
    request: BuiltRequest,
    private val onFrame: (ByteArray) -> Unit,
    private val onClose: (Int, String) -> Unit,
    private val onError: (Throwable) -> Unit,
) : BaseSession() {
    private val codec = BinaryFrameCodec()
    private val socket: WebSocket

    init {
        // Match TerminalSession: wait for the handshake before returning,
        // even though VNC has no in-band auth requirement — callers
        // expect `send()` to work as soon as `connectVnc()` returns.
        val openLatch = CountDownLatch(1)
        val openError = AtomicReference<Throwable?>(null)
        socket = transport.open(request.url, request.headers, object : WebSocketListener() {
            override fun onOpen(webSocket: WebSocket, response: Response) {
                openLatch.countDown()
            }
            override fun onMessage(webSocket: WebSocket, bytes: ByteString) {
                val out = mutableListOf<ByteArray>()
                codec.decodeBinary(bytes.toByteArray(), out)
                out.forEach(onFrame)
            }
            override fun onMessage(webSocket: WebSocket, text: String) {
                val out = mutableListOf<ByteArray>()
                codec.decode(text, out)
                out.forEach(onFrame)
            }
            override fun onClosed(webSocket: WebSocket, code: Int, reason: String) {
                if (openLatch.count > 0L) {
                    openError.set(IOException("WebSocket closed before open: $code $reason"))
                    openLatch.countDown()
                }
                closed = true
                onClose(code, reason)
            }
            override fun onFailure(webSocket: WebSocket, t: Throwable, response: Response?) {
                if (openLatch.count > 0L) {
                    openError.set(t)
                    openLatch.countDown()
                }
                if (!closed) onError(t)
                closed = true
            }
        })
        if (!openLatch.await(30L, TimeUnit.SECONDS)) {
            socket.cancel()
            throw IOException("WebSocket open timeout after 30s")
        }
        openError.get()?.let { err ->
            socket.cancel()
            throw IOException("WebSocket failed to open: ${err.message}", err)
        }
    }

    fun send(data: ByteArray) { socket.send(ByteString.of(*data)) }

    override fun close(code: Int, reason: String) {
        closed = true
        socket.close(code, reason)
    }
}

