class ConsoleConnector(
    private val auth: AuthAttacher = defaultAuth,
    private val transport: WebSocketTransport = defaultTransport,
) {
    fun connectTerminal(
        baseUrl: String,
        target: TerminalTarget,
        onMessage: (String) -> Unit = {},
        onClose: (Int, String) -> Unit = { _, _ -> },
        onError: (Throwable) -> Unit = {},
        issuer: TerminalTicketIssuer = DefaultTerminalTicketIssuer,
        httpClient: okhttp3.Call.Factory = ApiClient.defaultClient,
    ): TerminalSession {
        val (ticket, basePath) = issuer.issue(baseUrl, httpClient, target)
        val req = BuiltRequest(UpgradeUrlBuilder.build(baseUrl, basePath, ticket), auth.headers())
        return TerminalSession(transport, req, ticket, needsInbandAuth = true, onMessage, onClose, onError)
    }

    fun connectVnc(
        baseUrl: String,
        target: VncTarget,
        onFrame: (ByteArray) -> Unit = {},
        onClose: (Int, String) -> Unit = { _, _ -> },
        onError: (Throwable) -> Unit = {},
        issuer: VncTicketIssuer = DefaultVncTicketIssuer,
        httpClient: okhttp3.Call.Factory = ApiClient.defaultClient,
    ): VncSession {
        val (ticket, basePath) = issuer.issue(baseUrl, httpClient, target)
        val req = BuiltRequest(UpgradeUrlBuilder.build(baseUrl, basePath, ticket), auth.headers())
        return VncSession(transport, req, onFrame, onClose, onError)
    }
}

